private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       decimal settedEggs  = 0;
       if (GetCurrentColumnValue("SellableChicks") != null)
        SellableChicks= Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));

     if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs= Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

     groupSellableChicks+= SellableChicks;
     groupSettedEggs += settedEggs;
     TotalSelChicksGroup = (groupSellableChicks* 100m) / groupSettedEggs ;
    //---------- new logic for Infertile Eggs ------------------
      if (GetCurrentColumnValue("InfertileEggs") != null){
               InfertileEggs = Convert.ToDecimal(GetCurrentColumnValue("InfertileEggs"));
          }

    // --- SettedEggs ---
    decimal settedEggs_Infertile = 0;
    if (GetCurrentColumnValue("SettedEggs") != null){
             settedEggs_Infertile = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

        }
            // ---TOTAL -----
     TotalgroupInfertileEggs += InfertileEggs;
     TotalInfertileSettedEggs +=  settedEggs_Infertile;
    if (TotalInfertileSettedEggs != 0)
         TotalInfertileEggsGroup = (TotalgroupInfertileEggs * 100)  /  TotalInfertileSettedEggs ;
     //---------- new logic for NonHat Eggs ------------------
             // --- Declare values ---
    decimal nonHatEggs = 0;
    decimal settedEggs_NonHat = 0;

    // --- NonHatEggs ---
    if (GetCurrentColumnValue("NonHatEggs") != null)
        nonHatEggs = Convert.ToDecimal(GetCurrentColumnValue("NonHatEggs"));

    // --- SettedEggs ---
    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs_NonHat= Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    // --- Total percentage ---
     totaltNonHatEggsGroup += nonHatEggs;
    totalNonHatSettedEggsGroup += settedEggs_NonHat;
    if (totalNonHatSettedEggsGroup != 0)
        TotalNonHatEggsGroup = (totaltNonHatEggsGroup * 100m) / totalNonHatSettedEggsGroup ;
    //---------- new logic for Dead Eggs ------------------
     decimal Dead = 0;
    if (GetCurrentColumnValue("Deads") != null)
        Dead = Convert.ToDecimal(GetCurrentColumnValue("Deads"));
    groupDeadEggs += Dead;
    TotalDeadEggsGroup = (groupDeadEggs * 100m) / groupSettedEggs;
    //---------- new logic for Culls Eggs ------------------
    decimal Culls = 0;
    if (GetCurrentColumnValue("Culls") != null)
         Culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));
    groupCullsEggs += Culls;
    TotalCullsEggsGroup = (groupCullsEggs * 100m) / groupSettedEggs;
    //---------- new logic for Culls + SellableChicks ------------------
    decimal groupCullsSellableEggs  = 0;
    decimal CullsGroup  = 0;
    decimal SellableChicksGroup  = 0;
    decimal CullsTotalHatch = 0;
    decimal SellableChicksHatch = 0; 
    decimal settedEggs_TotalHatch = 0;
    decimal totalHatchChiksSettedEggsGroup  = 0;
    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs_TotalHatch= Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
    // --- Culls ---
    if (GetCurrentColumnValue("Culls") != null)
        CullsTotalHatch= Convert.ToDecimal(GetCurrentColumnValue("Culls"));

    // --- SellableChicks ---
    if (GetCurrentColumnValue("SellableChicks") != null)
        SellableChicksHatch = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));

    totalHatchChiksSettedEggsGroup  += settedEggs_TotalHatch;   
    CullsGroup += CullsTotalHatch;
    SellableChicksGroup += SellableChicksHatch ;
    groupCullsSellableEggs  = CullsGroup  + SellableChicksGroup  ;
    // --- Percentage ---
    TotalCullsSellableEggsGroup = (groupCullsSellableEggs * 100m) / totalHatchChiksSettedEggsGroup  ;
    //---------- new logic for Culls + SellableChicks ------------------
    decimal groupCullsSellableEggsChicks  = 0;
    // --- Culls ---
    if (GetCurrentColumnValue("Culls") != null)
        Culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

    // --- SellableChicks ---
    if (GetCurrentColumnValue("SellableChicks") != null)
        SellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));
        groupCullsSellableEggsChicks  += (Culls + SellableChicks );

    // --- Percentage ---
    TotalCullsSellableEggsGroupChicks = (groupCullsSellableEggsChicks  * 100m) / groupSettedEggs;


}


