private void xrTableCell15_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal InfertileEggs = 0;
    // --- InfertileEggs---
    if (GetCurrentColumnValue("InfertileEggs") != null){
              InfertileEggs = Convert.ToDecimal(GetCurrentColumnValue("InfertileEggs"));



        }


            // --- Equation ---
    decimal percentage = 0;
    if (settedEggsInfertile != 0)
        percentage = (InfertileEggs * 100m) / settedEggsInfertile ;

           // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = percentage.ToString("0.00"); // 2 decimals, adjust format if needed
    if (GetCurrentColumnValue("SettedEggs") != null){
            settedEggsInfertile = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
            settedEggsInfertileReport += settedEggsInfertile ;
        }
    TotalReportInfertileEggs += InfertileEggs;


}

