private void xrTableCell28_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal nonHatEggs = 0;
decimal settedEggs = 0;
// --- NonHatEggs ---
if (GetCurrentColumnValue("NonHatEggs") != null)
    nonHatEggs = Convert.ToDecimal(GetCurrentColumnValue("NonHatEggs"));

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Equation (row level %) ---
decimal percentage = 0;
if (settedEggs != 0)
    percentage = (nonHatEggs * 100m) / settedEggs;

// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level %
 if (GetCurrentColumnValue("SettedEggs") != null){
            settedEggsNonHatchery = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
            settedEggsNonHatcheryReport += settedEggsNonHatchery;


        }
        totalReportNonHatEggs += nonHatEggs;
  if (settedEggsNonHatcheryReport != 0)
    TotalPercentageNonHatEggs = (totalReportNonHatEggs * 100m) / settedEggsNonHatcheryReport ;

}


