private void xrTableCell20_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal deads = 0;
decimal settedEggs = 0;


// --- Deads ---
if (GetCurrentColumnValue("Deads") != null)
    deads = Convert.ToDecimal(GetCurrentColumnValue("Deads"));
//--- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));



// --- Equation (row level %) ---
decimal percentage = 0;
if (settedEggs != 0)
    percentage = (deads * 100m) / settedEggs;


// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null){
        settedEggsDeads = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
        totalsettedEggsDeadsReport += settedEggsDeads; 

    }
    totalReportDeads += deads;


if (totalsettedEggsDeadsReport != 0)
    TotalPercentageDeads = (totalReportDeads * 100m) / totalsettedEggsDeadsReport ;

}

