private void xrTableCell2_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal culls = 0;
decimal sellableChicks = 0;
decimal settedEggs = 0;

// --- Accumulators for totals ---
decimal totalReportCullsSellable = 0;
decimal totalReportSettedEggs = 0;

// --- Culls ---
if (GetCurrentColumnValue("Culls") != null)
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

// --- SellableChicks ---
if (GetCurrentColumnValue("SellableChicks") != null)
    sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));


// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));


// --- Equation (row level %) ---
decimal TotaChicksHatch = 0;
TotaChicksHatch = culls + sellableChicks ;

// --- Total percentage ---
// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = TotaChicksHatch.ToString("N0");  // Row level %
totalReportSettedEggs += settedEggs;
sellableChicksReport += sellableChicks ;
cullsReport += culls ;
totalReportCullsSellable = (sellableChicksReport + cullsReport );
if(totalReportSettedEggs != 0)
    TotalPercentageCullsSellable = (totalReportCullsSellable * 100m) / totalReportSettedEggs ;


}

