private void xrTableCell3_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal culls = 0;
decimal sellableChicks = 0;
decimal settedEggs = 0;


// --- Culls ---
if (GetCurrentColumnValue("Culls") != null)
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

// --- SellableChicks ---
if (GetCurrentColumnValue("SellableChicks") != null)
    sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Equation (row level %) ---
decimal percentage = 0;
if (settedEggs != 0)
    percentage = ((culls + sellableChicks) * 100m) / settedEggs;

// --- Total percentage ---
if (totalReportSettedEggs != 0)
    TotalPercentageCullsSellableChicks = (totalReportCullsSellable * 100m) / totalReportSettedEggs;

// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level %
if (GetCurrentColumnValue("SettedEggs") != null){
        CullsSelableSettedEggs_1 = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
        CullsSelableSettedEggsReport_1 += CullsSelableSettedEggs ;


    }
    totalReportCullsSellable_1 += (culls + sellableChicks);
   if(CullsSelableSettedEggsReport != 0)
    TotalPercentageCullsSellable = (totalReportCullsSellable* 100m) / CullsSelableSettedEggsReport;


}

